def {{nama_fungsi}}(a, b):
    """Return unified diff string."""
    import difflib
    diff = difflib.unified_diff(
        a.splitlines(keepends=True),
        b.splitlines(keepends=True),
        lineterm=''
    )
    return ''.join(diff)

def {{nama_fungsi}}(a, b, n={{n}}):
    """Dice coefficient dengan n-grams."""
    def ngrams(s, n):
        return set(s[i:i+n] for i in range(len(s)-n+1))
    if not a and not b:
        return 1.0
    A = ngrams(a.lower(), n)
    B = ngrams(b.lower(), n)
    if not A and not B:
        return 1.0
    inter = len(A & B)
    return 2 * inter / (len(A) + len(B)) if (len(A) + len(B)) else 0.0
